// src/components/Common/productCard.js
import React, { useState } from "react";

export default function ProductCard({ product, category, onEdit, onDelete, showActions = true }) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div 
      className="product-card"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className="product-card-inner">
        <div className="product-image">
          <img src={product.image || "https://cdn-icons-png.flaticon.com/512/1046/1046784.png"} alt={product.name} />
          {category && (
            <span className="product-category-badge" style={{ backgroundColor: category.color || "#22c55e" }}>
              {category.icon} {category.name}
            </span>
          )}
        </div>
        
        <div className="product-info">
          <h3 className="product-name">{product.name}</h3>
          <p className="product-price">
            <span className="price-icon">💰</span>
            {product.price} DA
          </p>
          {product.description && (
            <p className="product-description">{product.description}</p>
          )}
        </div>
        
        {showActions && (
          <div className={`product-actions ${isHovered ? "visible" : ""}`}>
            {onEdit && (
              <button className="action-btn edit" onClick={() => onEdit(product)}>
                ✏️ Modifier
              </button>
            )}
            {onDelete && (
              <button className="action-btn delete" onClick={() => onDelete(product)}>
                🗑️ Supprimer
              </button>
            )}
          </div>
        )}
      </div>
      
      <style jsx>{`
        .product-card {
          background: rgba(255, 255, 255, 0.08);
          backdrop-filter: blur(10px);
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.3s ease;
          border: 1px solid rgba(34, 197, 94, 0.3);
          position: relative;
          max-width: 350px;
          margin: 0 auto;
        }
        
        .product-card:hover {
          transform: translateY(-5px);
          box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
          border-color: rgba(34, 197, 94, 0.6);
        }
        
        .product-card-inner {
          position: relative;
        }
        
        .product-image {
          position: relative;
          height: 180px;
          overflow: hidden;
        }
        
        .product-image img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.3s ease;
        }
        
        .product-card:hover .product-image img {
          transform: scale(1.05);
        }
        
        .product-category-badge {
          position: absolute;
          top: 10px;
          right: 10px;
          padding: 4px 10px;
          border-radius: 20px;
          font-size: 0.7rem;
          font-weight: bold;
          color: white;
          background: rgba(0,0,0,0.6);
          backdrop-filter: blur(5px);
        }
        
        .product-info {
          padding: 15px;
          text-align: center;
        }
        
        .product-name {
          font-size: 1.1rem;
          font-weight: bold;
          color: white;
          margin-bottom: 8px;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        
        .product-price {
          display: inline-flex;
          align-items: center;
          gap: 5px;
          background: linear-gradient(135deg, #22c55e, #15803d);
          padding: 5px 12px;
          border-radius: 20px;
          color: white;
          font-size: 0.9rem;
          font-weight: bold;
          margin: 0 auto;
        }
        
        .price-icon {
          font-size: 0.8rem;
        }
        
        .product-description {
          color: rgba(255, 255, 255, 0.6);
          font-size: 0.75rem;
          margin-top: 10px;
          line-height: 1.4;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }
        
        .product-actions {
          position: absolute;
          bottom: 0;
          left: 0;
          right: 0;
          display: flex;
          gap: 8px;
          padding: 10px;
          background: linear-gradient(0deg, rgba(0,0,0,0.9), rgba(0,0,0,0.7));
          transform: translateY(100%);
          transition: transform 0.3s ease;
        }
        
        .product-actions.visible {
          transform: translateY(0);
        }
        
        .action-btn {
          flex: 1;
          padding: 8px;
          border: none;
          border-radius: 12px;
          font-size: 0.7rem;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.3s;
        }
        
        .action-btn.edit {
          background: linear-gradient(135deg, #3b82f6, #1d4ed8);
          color: white;
        }
        
        .action-btn.edit:hover {
          transform: scale(1.02);
          box-shadow: 0 2px 10px rgba(59,130,246,0.4);
        }
        
        .action-btn.delete {
          background: linear-gradient(135deg, #ef4444, #b91c1c);
          color: white;
        }
        
        .action-btn.delete:hover {
          transform: scale(1.02);
          box-shadow: 0 2px 10px rgba(239,68,68,0.4);
        }
        
        @media (max-width: 480px) {
          .product-image {
            height: 140px;
          }
          
          .product-name {
            font-size: 0.9rem;
          }
          
          .product-price {
            font-size: 0.8rem;
            padding: 4px 10px;
          }
        }
      `}</style>
    </div>
  );
}
